[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ResetAppPackage,[switch]$ClearWebCache,[switch]$RepairWebView2,[switch]$ResetNetwork,[switch]$Force,[string]$OutputPath="$env:USERPROFILE\Desktop\CopilotRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ResetAppPackage-or$ClearWebCache-or$RepairWebView2-or$ResetNetwork)){throw'Choose at least one repair action.'}
$pkg=Get-AppxPackage *Copilot* -ErrorAction SilentlyContinue|Select-Object -First 1;$pkg|Export-Clixml (Join-Path $OutputPath 'package-before.xml')
if($ClearWebCache){$p=Get-Process msedge,msedgewebview2 -ErrorAction SilentlyContinue;if($p-and-not$Force){throw'Close Copilot and Edge or use -Force.'};if($p){$p|Stop-Process -Force};foreach($x in @("$env:LOCALAPPDATA\Microsoft\Edge\User Data\Default\Cache","$env:LOCALAPPDATA\Microsoft\EdgeWebView\Default\Cache")){if(Test-Path $x){if($PSCmdlet.ShouldProcess($x,'Clear Copilot web cache')){Get-ChildItem $x -Force -ErrorAction SilentlyContinue|Remove-Item -Recurse -Force -ErrorAction SilentlyContinue}}};L'Web cache cleared.'}
if($ResetAppPackage){if(-not$pkg){throw'Copilot app package not found.'};if($PSCmdlet.ShouldProcess($pkg.PackageFullName,'Reset app package')){Reset-AppxPackage -Package $pkg.PackageFullName;L'Copilot package reset.'}}
if($RepairWebView2){$setup=Get-ChildItem "$env:ProgramFiles(x86)\Microsoft\EdgeWebView\Application" -Filter setup.exe -Recurse -ErrorAction SilentlyContinue|Select-Object -First 1 -Expand FullName;if(-not$setup){throw'WebView2 setup not found.'};if($PSCmdlet.ShouldProcess('WebView2 Runtime','Repair')){Start-Process $setup '--repair --msedgewebview --system-level' -Wait;L'WebView2 repaired.'}}
if($ResetNetwork-and$PSCmdlet.ShouldProcess('Network stack','Flush DNS and reset Winsock')){Clear-DnsClientCache;netsh winsock reset|Tee-Object -FilePath $Log -Append;L'Network reset completed; reboot may be required.'}
L'Repair workflow finished.'